function loadGame() { try { const state=JSON.parse(localStorage.getItem(SAVE_KEY)); if(!state||state.version!==1||!Number.isInteger(state.mapIndex)||!maps[state.mapIndex]) return false; currentMapIndex=state.mapIndex; path=maps[currentMapIndex].path.map(point=>({...point})); pads=maps[currentMapIndex].pads.map(point=>({...point})); pathLength=calculatePathLength(); if(Array.isArray(state.unlockedMaps)) state.unlockedMaps.forEach((value,index)=>{if(index<unlockedMaps.length)unlockedMaps[index]=!!value;}); Object.keys(baseUpgrades).forEach(id=>{if(Number.isFinite(state.baseUpgrades?.[id]))baseUpgrades[id]=Math.max(0,Math.min(getUpgradeMax(id),Math.floor(state.baseUpgrades[id])));}); inventory=freshInventory(); Object.entries(state.inventory||{}).forEach(([id,levels])=>{if(inventory[id]&&Array.isArray(levels))inventory[id]=levels.filter(level=>Number.isInteger(level)&&level>0).map(level=>Math.min(level,getMaxLevel({type:types[id]})));}); const savedLayouts=Array.isArray(state.mapTowerStates)?state.mapTowerStates:null; mapTowerStates.forEach((_,index)=>{mapTowerStates[index]=Array.isArray(savedLayouts?.[index])?savedLayouts[index]:index===currentMapIndex?(state.towers||[]):[];}); restoreTowerLayout(mapTowerStates[currentMapIndex]); gold=Math.max(0,Math.floor(state.gold||0)); lives=Math.max(1,Math.floor(state.lives||getStartingLives())); wave=Math.max(0,Math.floor(state.wave||0)); drawCost=Math.max(BASE_DRAW_COST,Math.floor(state.drawCost||BASE_DRAW_COST)); enemies=Array.isArray(state.enemies)?state.enemies.map(restoreSavedEnemy).filter(Boolean):[]; spawnQueue=Array.isArray(state.spawnQueue)?state.spawnQueue.filter(Number.isInteger):[]; spawnCooldown=Math.max(0,Number(state.spawnCooldown)||0); running=!!state.running&&(enemies.length>0||spawnQueue.length>0); autoWave=!!state.autoWave; selected=inventory[state.selected]?.length?state.selected:Object.keys(inventory).find(id=>inventory[id].length)||null; camera.x=Math.max(0,Math.min(W,state.camera?.x||W/2));camera.y=Math.max(0,Math.min(H,state.camera?.y||H/2));camera.zoom=Math.max(.7,Math.min(2.2,state.camera?.zoom||1));gameOver=false;ui.waveButton.disabled=running;ui.waveButton.textContent=running?'DEFENDING':wave?'NEXT WAVE >':'START WAVE >';return true; } catch { return false; } }
function updateCamera(dt) { const left=cameraKeys.has('a'), right=cameraKeys.has('d'), up=cameraKeys.has('w'), down=cameraKeys.has('s'); if(!left&&!right&&!up&&!down) return; const length=Math.hypot((right?1:0)-(left?1:0),(down?1:0)-(up?1:0))||1, speed=460/camera.zoom; camera.x+=((right?1:0)-(left?1:0))/length*speed*dt; camera.y+=((down?1:0)-(up?1:0))/length*speed*dt; camera.x=Math.max(0,Math.min(W,camera.x)); camera.y=Math.max(0,Math.min(H,camera.y)); }

function renderInventory() {
  const categories=[['all','ALL'],['spark','ELECTRIC'],['cannon','CANNON'],['thorns','THORNS']];
  if(ui.towerCategories)ui.towerCategories.innerHTML=categories.map(([id,label])=>`<button data-category="${id}" class="${towerCategory===id?'active':''}" title="Show ${label.toLowerCase()} towers">${label}</button>`).join('');
  ui.inventory.innerHTML = Object.entries(types).filter(([,type])=>towerCategory==='all'||type.kind===towerCategory).map(([id, type]) => {
    const levels = inventory[id], amount = levels.length, highest = amount ? Math.max(...levels) : 0;
    return `<button class="inventory-slot ${selected === id ? 'selected' : ''}" data-tower="${id}" ${amount ? '' : 'disabled'}><span class="inventory-icon ${type.kind}">${type.icon}</span><span class="inventory-name">${type.name}</span><span class="inventory-grade grade-${type.grade}">${type.gradeLabel}</span><span class="inventory-count">OWNED <b>${amount}</b>${highest > 1 ? ` | MAX L${highest}` : ''}</span></button>`;
  }).join('');
}
