function renderStats() { if(!ui.statsPanel) return; const cards=[['TOTAL KILLS',overallStats.kills],['NORMAL KILLS',overallStats.normalKills],['ELITE KILLS',overallStats.eliteKills],['BOSS KILLS',overallStats.bossKills],['SUPPLIES EARNED',overallStats.suppliesEarned],['ROULETTE DRAWS',overallStats.draws],['WAVES CLEARED',overallStats.wavesCleared],['HIGHEST WAVE',overallStats.highestWave],['DEFEATS',overallStats.deaths]]; ui.statsPanel.innerHTML=`<div class="stats-head"><strong>OVERALL STATS</strong><button data-close-stats>CLOSE</button></div><div class="stats-grid">${cards.map(([label,value])=>`<article><small>${label}</small><b>${value.toLocaleString()}</b></article>`).join('')}</div><p>Saved automatically in this browser.</p>`; }
function upgradeCost(tower) { return tower.level * 90; }
function getMaxLevel(tower) { return 3 + grades.findIndex(grade => grade.id === tower.type.grade); }
function getNextGradeType(tower) { const currentGrade=grades.findIndex(grade=>grade.id===tower.type.grade), archetype=archetypes.find(entry=>entry.id===tower.type.id.slice(tower.type.grade.length+1)); return currentGrade<grades.length-1&&archetype?types[`${grades[currentGrade+1].id}-${archetype.id}`]:null; }
function getStartingLives() { return 20 + baseUpgrades.fortify * 5; }
function getRouletteLevel() { return baseUpgrades.roulette + 1; }
function getUpgradeMax(id) { return id==='roulette'?39:id==='slots'?Math.max(...maps.map(map=>map.pads.length-BASE_INSTALL_SLOTS)):10; }
function getMapSlotUpgradeCap(mapIndex=currentMapIndex) { return maps[mapIndex].pads.length-BASE_INSTALL_SLOTS; }
function getOpenBuildPadCount() { return Math.min(pads.length,BASE_INSTALL_SLOTS+baseUpgrades.slots); }
function isPadUnlocked(pad) { return !!pad.tower||pads.indexOf(pad)<getOpenBuildPadCount(); }
function getStageDifficulty() { return maps[currentMapIndex].stage; }
function getDifficultyLabel() { return ['NORMAL','HARD','EXTREME'][getStageDifficulty()-1]; }
function getGradeChance(grade) { const luck=baseUpgrades.luck; if(grade.id==='common') return Math.max(10,50-luck*4); if(grade.id==='uncommon') return Math.max(8,26-luck); if(grade.id==='rare') return 14+luck*2; if(grade.id==='epic') return 7+luck*2; if(grade.id==='legendary') return 3+luck; return grade.chance+luck*.12; }
function getTowerRange(tower) { return tower.type.range + (tower.level - 1) * 18; }
function getTowerDamage(tower) { return Math.round(tower.type.damage * (1 + (tower.level - 1) * .55) * (1 + baseUpgrades.power * .1)); }
function getTowerFireRate(tower) { return tower.type.fireRate * Math.pow(.86, tower.level - 1); }
function getGradeTier(tower) { return grades.findIndex(grade=>grade.id===tower.type.grade); }
function getAbilityText(tower) { const tier=getGradeTier(tower), bonus=tier+1; switch(tower.type.ability){case'chain':return `CHAIN ×${bonus}`;case'shock':return `SHOCK SLOW ${Math.round((.45+tier*.12)*100)/100}s`;case'prism':return `PRISM SPLIT ×${bonus}`;case'storm':return `STORM CHAIN ×${bonus+1}`;case'splash':return `ROOT SPLASH ${42+tier*10}`;case'mortar':return `MORTAR SPLASH ${68+tier*12}`;case'burn':return `BURN ${2+tier*.4}s`;case'root':return `ROOT SLOW ${Math.round((.35+tier*.1)*100)/100}s`;case'freeze':return `FREEZE ${Math.round((.7+tier*.12)*100)/100}s`;case'poison':return `POISON ${2+tier*.35}s`;default:return 'TOWER SKILL';} }
function matchingTower(tower) { return towers.find(other => other !== tower && other.type.id === tower.type.id && other.level === tower.level); }
function renderUpgradePanel() {
  if(!selectedTower || !towers.includes(selectedTower)) { ui.upgradePanel.className='upgrade-panel empty'; ui.upgradePanel.innerHTML='<span class="upgrade-title">UPGRADE</span><span class="upgrade-detail">Click an installed tower.</span>'; return; }
  const maxLevel = getMaxLevel(selectedTower), maxed = selectedTower.level >= maxLevel, nextGradeType=getNextGradeType(selectedTower), canFuse=!maxed||!!nextGradeType, cost = upgradeCost(selectedTower), match = matchingTower(selectedTower), fuseLabel=maxed&&nextGradeType?`PROMOTE ${nextGradeType.gradeLabel}`:maxed?'FUSE MAXED':match?'FUSE MATCH':'FUSE NEEDS MATCH';
  ui.upgradePanel.className='upgrade-panel';
  ui.upgradePanel.innerHTML=`<span class="upgrade-title">${selectedTower.type.name} LV ${selectedTower.level}/${maxLevel}</span><span class="upgrade-detail">DMG ${getTowerDamage(selectedTower)} | RNG ${getTowerRange(selectedTower)}</span><span class="upgrade-detail">SKILL: ${getAbilityText(selectedTower)}</span><button data-upgrade ${maxed || gold < cost ? 'disabled' : ''}>${maxed ? 'MAX LEVEL' : `UPGRADE ${cost}`}</button><button data-fuse ${!canFuse || !match ? 'disabled' : ''}>${fuseLabel}</button><button class="store" data-store>STORE TOWER</button>`;
}
function updateUI() { const missingSupplies=Math.max(0,drawCost-gold), rouletteLevel=getRouletteLevel(); ui.gold.textContent = gold; ui.lives.textContent = lives; ui.wave.textContent = wave; if(ui.drawCost) ui.drawCost.textContent = drawCost; if(ui.rouletteLevel) ui.rouletteLevel.textContent=`LV ${rouletteLevel}`; ui.rollButton.title=missingSupplies ? `Tower roulette costs ${drawCost}. Need ${missingSupplies} more supplies.` : rouletteLevel<10 ? `Draw a random tower for ${drawCost} supplies. Epic and Legendary unlock at roulette level 10.` : rouletteLevel<20 ? `Draw a random tower for ${drawCost} supplies. Mythic and Ancient unlock at roulette level 20.` : rouletteLevel<40 ? `Draw a random tower for ${drawCost} supplies. Celestial and higher grades unlock at roulette level 40.` : `Draw a random tower for ${drawCost} supplies`; ui.rollButton.classList.toggle('needs-supplies',!!missingSupplies&&!isDrawing); ui.difficulty.textContent=`S${getStageDifficulty()} ${getDifficultyLabel()}`; renderInventory(); renderUpgradePanel(); updateMapButton(); updateAutoWaveButton(); if(ui.statsPanel&&!ui.statsPanel.hidden)renderStats(); }
