function calculatePathLength() { return path.slice(0,-1).reduce((sum,p,i) => sum + distance(p,path[i+1]), 0); }
let pathLength = calculatePathLength();

function makeEnemy(index) { const stage=getStageDifficulty(), boss = wave > 0 && wave % 30 === 0 && index === 0, elite = !boss && wave % 4 === 0 && index === 0; const type=boss ? wave30Boss : elite ? eliteTypes[Math.floor(wave/4)%eliteTypes.length] : enemyTypes[(wave*3+index)%enemyTypes.length]; const baseHp=(boss ? 5400+wave*100 : elite ? 310+wave*50 : 58+wave*24)*(1+(stage-1)*.4), hp=Math.round(baseHp*type.hp), damage=type.damage+stage-1; return {progress:PORTAL_PROGRESS, spawnProgress:PORTAL_PROGRESS, speed:(38+wave*3.4)*type.speed*(1+(stage-1)*.1), hp, maxHp:hp, damage, reward:boss ? 500 : elite ? 25 : 10, r:type.r, elite, boss, type, slow:0, slowFactor:1, poison:0, poisonDamage:0, burn:0, burnDamage:0, statusTick:0, hit:0}; }
