function renderBaseUpgradeChoices() { const cards=[{id:'luck',icon:'D6',name:'LUCKY DICE',detail:'Better draw odds for Rare and higher-grade towers.'},{id:'fortify',icon:'HP',name:'FORTIFIED KEEP',detail:'Start each new defense with +5 keep health.'},{id:'power',icon:'DMG',name:'BATTLE DOCTRINE',detail:'All tower damage increases by 10%.'},{id:'roulette',icon:'LV',name:'ROULETTE MASTERY',detail:'Epic/Legendary: LV 10. Mythic/Ancient: LV 20. Celestial+: LV 40.'},{id:'slots',icon:'PAD',name:'EXPAND BUILD SLOTS',detail:`Add one build slot. Stage ${getStageDifficulty()} max: ${maps[currentMapIndex].pads.length}.`}]; const nextMap=unlockedMaps.findIndex(unlocked=>!unlocked); if(nextMap!==-1){const addedGrades=nextMap===1?'Mythic and Ancient grades.':'Celestial, Divine, and Transcendent grades.';cards.push({id:'map',icon:'MAP',name:`UNLOCK STAGE ${maps[nextMap].stage}`,detail:`Unlock ${maps[nextMap].name} and ${addedGrades}`,mapIndex:nextMap});} ui.baseUpgradeChoices.innerHTML=cards.map(card=>{const level=baseUpgrades[card.id],slotCap=getMapSlotUpgradeCap(),maxed=card.id==='roulette'?level>=getUpgradeMax('roulette'):card.id==='slots'?level>=slotCap:card.id!=='map'&&level>=10,levelText=card.id==='map'?'UNLOCK':card.id==='roulette'?maxed?'LV 40 MAX':`LV ${getRouletteLevel()} -> ${getRouletteLevel()+1}`:card.id==='slots'?maxed?`S${getStageDifficulty()} ${getOpenBuildPadCount()}/${pads.length} MAX`:`S${getStageDifficulty()} ${getOpenBuildPadCount()}/${pads.length} -> ${getOpenBuildPadCount()+1}/${pads.length}`:maxed?'MAX':`LV ${level} -> ${level+1}`;return `<button data-base-upgrade="${card.id}" ${maxed?'disabled':''}><span class="base-upgrade-icon">${card.icon}</span><span class="base-upgrade-name">${card.name}</span><span class="base-upgrade-detail">${card.detail}</span><span class="base-upgrade-level">${levelText}</span></button>`;}).join(''); }
function showDeathUpgrades() { ui.modalTitle.textContent='KEEP FALLEN'; ui.modalText.textContent='Choose one base upgrade before your next defense.'; ui.startButton.hidden=true; renderBaseUpgradeChoices(); ui.baseUpgradeChoices.hidden=false; ui.modal.classList.add('open'); }
function restartAfterDefeat() { clearTimeout(drawTimer); clearInterval(drawSpinTimer); clearTimeout(autoWaveTimer); autoWave=false; isDrawing=false; ui.rollButton.disabled=false; ui.rollButton.classList.remove('rolling'); setRouletteTower(); drawCost+=DEATH_DRAW_COST_INCREASE; gold=Math.max(gold,drawCost); lives=getStartingLives(); wave=0; running=false; gameOver=false; enemies=[]; shots=[]; particles=[]; spawnQueue=[]; towers.forEach(tower=>{tower.level=1;tower.cooldown=0;tower.pulse=0;}); mapTowerStates.forEach(layout=>layout.forEach(tower=>tower.level=1)); Object.keys(inventory).forEach(id=>{inventory[id]=inventory[id].map(()=>1);}); selected=Object.keys(inventory).find(id=>inventory[id].length)||selected; selectedTower=null; fusionMode=false; resetView(); ui.waveButton.disabled=false; ui.waveButton.textContent='START WAVE >'; updateUI(); }
