function reset() { clearTimeout(drawTimer); clearInterval(drawSpinTimer); clearTimeout(autoWaveTimer); autoWave=false; isDrawing=false; ui.rollButton.disabled=false; ui.rollButton.classList.remove('rolling'); setRouletteTower(); gold=320; lives=getStartingLives(); wave=0; drawCost=BASE_DRAW_COST; running=false; gameOver=false; towers=[]; mapTowerStates.forEach((_,index)=>mapTowerStates[index]=[]); enemies=[]; shots=[]; particles=[]; spawnQueue=[]; inventory=freshInventory(); selected='common-spark-coil'; selectedTower=null; fusionMode=false; resetView(); pads.forEach(p => delete p.tower); ui.waveButton.disabled=false; ui.waveButton.textContent='START WAVE >'; updateUI(); }

function choose(type) { if(!inventory[type] || !inventory[type].length) return say('Draw this tower before selecting it.'); selected = type; renderInventory(); say(`${types[type].name} selected.`); }
function selectTower(tower) { fusionMode=false; selectedTower=tower; renderUpgradePanel(); say(`${tower.type.name} selected. Level ${tower.level}.`); }
function upgradeTower() { if(!selectedTower || !towers.includes(selectedTower)) return; if(selectedTower.level >= getMaxLevel(selectedTower)) return say('This tower is already at max level.'); const cost=upgradeCost(selectedTower); if(gold < cost) return say(`You need ${cost-gold} more supplies to upgrade.`); gold-=cost; selectedTower.level++; updateUI(); say(`${selectedTower.type.name} upgraded to level ${selectedTower.level}!`); }
function startFusion() { if(!selectedTower || (selectedTower.level >= getMaxLevel(selectedTower) && !getNextGradeType(selectedTower))) return; if(!matchingTower(selectedTower)) return say('Fusion needs another tower of the same type and level.'); fusionMode=true; say(`Fusion ready: click another ${selectedTower.type.name} level ${selectedTower.level}.`); }
function fuseWith(tower) { if(!fusionMode || !selectedTower) return; if(tower === selectedTower) return say('Click a different matching tower to fuse.'); if(tower.type.id !== selectedTower.type.id || tower.level !== selectedTower.level) return say('Fusion requires the same tower type and level.'); const promoting=selectedTower.level>=getMaxLevel(selectedTower), nextGradeType=promoting&&getNextGradeType(selectedTower); if(promoting&&!nextGradeType) return say('Transcendent towers are already at the final level cap.'); towers.splice(towers.indexOf(tower),1); if(tower.pad) delete tower.pad.tower; if(nextGradeType){selectedTower.type=nextGradeType;selectedTower.level=1;}else selectedTower.level++; selectedTower.pulse=.55; fusionMode=false; for(let i=0;i<16;i++) particles.push({x:selectedTower.x,y:selectedTower.y,vx:(Math.random()-.5)*180,vy:(Math.random()-.5)*180,life:.6,size:4+Math.random()*4,color:'#ffe779'}); updateUI(); say(nextGradeType?`Fusion promotion! ${selectedTower.type.name} is now level 1.`:`Fusion complete! ${selectedTower.type.name} is now level ${selectedTower.level}.`); }
function storeTower() { if(!selectedTower || !towers.includes(selectedTower)) return; const tower=selectedTower; inventory[tower.type.id].push(tower.level); inventory[tower.type.id].sort((a,b)=>b-a); towers.splice(towers.indexOf(tower),1); if(tower.pad) delete tower.pad.tower; selectedTower=null; fusionMode=false; selected=tower.type.id; updateUI(); say(`${tower.type.name} level ${tower.level} stored in inventory.`); }
function deployThornsOnPath(x,y) { if(!selected || !inventory[selected].length) return say('Select a thorn tower you own in the inventory.'); const type=types[selected], point=closestPathPoint(x,y); if(point.distance>36) return say('Thorn towers must be installed directly on the path.'); if(towers.some(t=>t.pathTrap&&distance(t,point)<44)) return say('Another thorn tower is already too close.'); const level=inventory[selected].sort((a,b)=>b-a).shift(), tower={x:point.x,y:point.y,type,cooldown:Math.random()*.25,angle:point.angle,pulse:0,level,pad:null,pathTrap:true}; towers.push(tower); selectedTower=tower; fusionMode=false; if(!inventory[selected].length) selected=Object.keys(inventory).find(id=>inventory[id].length)||null; updateUI(); say(`${type.name} level ${level} installed on the path.`); }
function buildAt(pad) { if(!selected || !inventory[selected].length) return say('Select a tower you own in the inventory.'); const type = types[selected]; if(type.kind==='thorns') return say('Thorn towers must be installed directly on the path.'); const level=inventory[selected].sort((a,b)=>b-a).shift(); const tower = {x:pad.x,y:pad.y,type,cooldown:Math.random()*.25,angle:-Math.PI/2,pulse:0,level,pad}; pad.tower=tower; towers.push(tower); selectedTower=tower; fusionMode=false; if(!inventory[selected].length) selected = Object.keys(inventory).find(id => inventory[id].length) || null; updateUI(); say(`${type.name} level ${level} installed.`); }
function setRouletteTower(type) { if(!ui.rouletteTower) return; ui.rouletteTower.textContent=type?type.icon:'TWR'; ui.rouletteTower.style.setProperty('--tower-color',type?type.color:'#d5c8f4'); ui.rouletteTower.title=type?type.name:'Tower roulette'; }
function finishRoulette() { clearTimeout(drawTimer); clearInterval(drawSpinTimer); isDrawing=false; ui.rollButton.disabled=false; ui.rollButton.classList.remove('rolling'); }
function getMapGradeCap() { return unlockedMaps[2]?grades.length-1:unlockedMaps[1]?6:4; }
function getRouletteGrades() { const level=getRouletteLevel(); return grades.filter((grade,index)=>index<=getMapGradeCap()&&(level>=10||index<=2)&&(level>=20||index<=4)&&(level>=40||index<=6)); }
function drawTower() { if(isDrawing) return; if(gold < drawCost) return say(`Tower roulette costs ${drawCost}. You need ${drawCost-gold} more supplies.`); const allowedGrades=getRouletteGrades(), previews=Object.values(types).filter(type=>allowedGrades.some(grade=>grade.id===type.grade)); if(!previews.length) return say('No towers are available for the roulette.'); const cost=drawCost; isDrawing=true; gold-=cost; recordStats({draws:1}); ui.rollButton.disabled=true; ui.rollButton.classList.add('rolling'); updateUI(); try { setRouletteTower(previews[Math.floor(Math.random()*previews.length)]); drawSpinTimer=setInterval(()=>{setRouletteTower(previews[Math.floor(Math.random()*previews.length)]);},65); drawTimer=setTimeout(()=>{try { let roll=Math.random()*allowedGrades.reduce((sum,grade)=>sum+getGradeChance(grade),0), grade=allowedGrades[0]; for(const entry of allowedGrades){roll-=getGradeChance(entry);if(roll<=0){grade=entry;break;}} const candidates=previews.filter(type=>type.grade===grade.id); const drawn=candidates[Math.floor(Math.random()*candidates.length)]; if(!drawn) throw new Error('roulette result missing'); setRouletteTower(drawn); inventory[drawn.id].push(1); selected=drawn.id;towerCategory=drawn.kind; say(`Tower roulette: ${drawn.name}!`); } catch { gold+=cost; say('Roulette error recovered. Your supplies were refunded.'); } finally { finishRoulette(); updateUI(); } },850); } catch { gold+=cost; finishRoulette(); updateUI(); say('Roulette error recovered. Your supplies were refunded.'); } }

function eventToWorld(event) { const rect=canvas.getBoundingClientRect(), screenX=(event.clientX-rect.left)*W/rect.width, screenY=(event.clientY-rect.top)*H/rect.height; return {x:(screenX-W/2)/camera.zoom+camera.x, y:(screenY-H/2)/camera.zoom+camera.y, screenX, screenY}; }
canvas.addEventListener('click', event => { if(gameOver) return; const {x,y}=eventToWorld(event), pad=pads.find(p=>distance({x,y},p)<36), selectedType=selected&&types[selected]; if(pad){if(!isPadUnlocked(pad)) return say(`Build slot locked. Upgrade slots after defeat (${getOpenBuildPadCount()}/${pads.length}).`);if(pad.tower) return fusionMode ? fuseWith(pad.tower) : selectTower(pad.tower); if(fusionMode) return say('Fusion needs a matching installed tower.'); return buildAt(pad);} const pathTower=towers.find(t=>t.pathTrap&&distance({x,y},t)<28); if(pathTower) return fusionMode ? fuseWith(pathTower) : selectTower(pathTower); if(fusionMode) return say('Fusion needs a matching installed tower.'); if(selectedType&&selectedType.kind==='thorns') return deployThornsOnPath(x,y); say('Click a glowing hexagonal build zone.'); });
canvas.addEventListener('wheel', event => { event.preventDefault(); const before=eventToWorld(event), nextZoom=Math.max(.7,Math.min(2.2,camera.zoom*(event.deltaY>0?.9:1.1))); if(nextZoom===camera.zoom) return; camera.zoom=nextZoom; const after=eventToWorld(event); camera.x+=before.x-after.x; camera.y+=before.y-after.y; }, {passive:false});
ui.inventory.addEventListener('click', event => { const slot = event.target.closest('button[data-tower]'); if(slot) choose(slot.dataset.tower); });
if(ui.towerCategories) ui.towerCategories.addEventListener('click', event => { const button=event.target.closest('[data-category]'); if(!button) return; towerCategory=button.dataset.category; renderInventory(); say(`${button.textContent} tower category selected.`); });
ui.inventory.addEventListener('wheel', event => { event.preventDefault(); ui.inventory.scrollLeft += event.deltaY + event.deltaX; }, {passive:false});
ui.upgradePanel.addEventListener('click', event => { if(event.target.closest('[data-upgrade]')) upgradeTower(); if(event.target.closest('[data-fuse]')) startFusion(); if(event.target.closest('[data-store]')) storeTower(); });
ui.baseUpgradeChoices.addEventListener('click', event => { const button=event.target.closest('[data-base-upgrade]'); if(button) chooseBaseUpgrade(button.dataset.baseUpgrade); });
ui.resetViewButton.addEventListener('click', () => { resetView(); say('View reset.'); });
ui.mapButton.addEventListener('click', () => { setMap((currentMapIndex+1)%maps.length); });
if(ui.previousMapButton) ui.previousMapButton.addEventListener('click', () => { setMap((currentMapIndex-1+maps.length)%maps.length); });
ui.saveButton.addEventListener('click', saveGame);
if(ui.indexButton) ui.indexButton.addEventListener('click', () => { const opening=ui.indexPanel.hidden; ui.indexPanel.hidden=!opening; if(opening) renderIndex(); });
if(ui.indexPanel) ui.indexPanel.addEventListener('click', event => { if(event.target.closest('[data-close-index]')) ui.indexPanel.hidden=true; });
if(ui.statsButton) ui.statsButton.addEventListener('click', () => { const opening=ui.statsPanel.hidden; ui.statsPanel.hidden=!opening; if(opening) renderStats(); });
if(ui.statsPanel) ui.statsPanel.addEventListener('click', event => { if(event.target.closest('[data-close-stats]')) ui.statsPanel.hidden=true; });
ui.autoWaveButton.addEventListener('click', () => { autoWave=!autoWave; clearTimeout(autoWaveTimer); updateAutoWaveButton(); say(`Auto wave ${autoWave?'enabled':'disabled'}.`); if(autoWave&&!running&&!gameOver) startWave(); });
ui.waveButton.addEventListener('click', startWave); ui.rollButton.addEventListener('click', drawTower);
ui.startButton.addEventListener('click', () => { if(gameOver) reset(); ui.baseUpgradeChoices.hidden=true; ui.modal.classList.remove('open'); });
window.addEventListener('keydown', e => { const key=e.key.toLowerCase(); if(['w','a','s','d'].includes(key)){cameraKeys.add(key);e.preventDefault();} if(e.key === ' '){ e.preventDefault(); startWave(); } if(['1','2','3'].includes(e.key)) choose(['common-spark-coil','common-root-cannon','common-thorn-garden'][+e.key-1]); });
window.addEventListener('keyup', e => { cameraKeys.delete(e.key.toLowerCase()); });

function hurt(enemy, amount, color) { enemy.hp -= amount; enemy.hit = .12; for(let i=0;i<5;i++) particles.push({x:enemy.x,y:enemy.y,vx:(Math.random()-.5)*90,vy:(Math.random()-.5)*90,life:.35,size:2+Math.random()*3,color}); if(enemy.hp <= 0){ gold += enemy.reward; recordStats({kills:1,normalKills:enemy.boss||enemy.elite?0:1,eliteKills:enemy.elite?1:0,bossKills:enemy.boss?1:0,suppliesEarned:enemy.reward}); particles.push({x:enemy.x,y:enemy.y,vx:0,vy:0,life:.55,size:enemy.r*2.6,color:'#ffe779',burst:true}); enemies.splice(enemies.indexOf(enemy),1); if(enemy.boss){const upgraded=baseUpgrades.roulette<getUpgradeMax('roulette')&&Math.random()<.5;if(upgraded){baseUpgrades.roulette++;persistPermanentProgress();}say(upgraded?`BOSS DEFEATED! +500 supplies. Roulette Mastery is now LV ${getRouletteLevel()}!`:`BOSS DEFEATED! +500 supplies. Roulette Mastery stayed at LV ${getRouletteLevel()}.`);} updateUI(); } }
function applySlow(enemy, duration, factor) { enemy.slow=Math.max(enemy.slow||0,duration); enemy.slowFactor=Math.min(enemy.slowFactor||1,factor); }
function applyDot(enemy, kind, duration, damage) { enemy[kind]=Math.max(enemy[kind]||0,duration); enemy[`${kind}Damage`]=Math.max(enemy[`${kind}Damage`]||0,damage); enemy.statusTick=0; }
function nearbyEnemies(target, radius, count) { return enemies.filter(enemy=>enemy!==target&&distance(enemy,target)<radius).sort((a,b)=>b.progress-a.progress).slice(0,count); }
function applyThornAbility(tower, enemy) { const tier=getGradeTier(tower); if(tower.type.ability==='root') applySlow(enemy,.35+tier*.1,.74-tier*.035); if(tower.type.ability==='freeze') applySlow(enemy,.7+tier*.12,.54-tier*.035); if(tower.type.ability==='poison') applyDot(enemy,'poison',2+tier*.35,getTowerDamage(tower)*(.16+tier*.035)); }
function triggerShotAbility(shot) { const tier=getGradeTier(shot.tower), ability=shot.tower.type.ability, target=shot.target, targetAlive=enemies.includes(target); if(ability==='chain') nearbyEnemies(target,70,1+tier).forEach(enemy=>hurt(enemy,shot.damage*(.42+tier*.035),shot.color)); if(ability==='shock'&&targetAlive) applySlow(target,.45+tier*.12,.7-tier*.035); if(ability==='prism') nearbyEnemies(target,92,1+tier).forEach(enemy=>hurt(enemy,shot.damage*(.48+tier*.035),shot.color)); if(ability==='storm') nearbyEnemies(target,98,2+tier).forEach(enemy=>hurt(enemy,shot.damage*(.5+tier*.035),shot.color)); if(ability==='splash') nearbyEnemies(target,42+tier*10,99).forEach(enemy=>hurt(enemy,shot.damage*(.5+tier*.03),shot.color)); if(ability==='mortar') nearbyEnemies(target,68+tier*12,99).forEach(enemy=>hurt(enemy,shot.damage*(.62+tier*.035),shot.color)); if(ability==='burn'&&targetAlive) applyDot(target,'burn',2+tier*.4,shot.damage*(.22+tier*.04)); }
function update(dt) {
  if(running && spawnQueue.length){ spawnCooldown -= dt; if(spawnCooldown <= 0){ enemies.push(makeEnemy(spawnQueue.shift())); spawnCooldown = .58; } }
  for(const enemy of [...enemies]) { enemy.poison=Math.max(0,(enemy.poison||0)-dt); enemy.burn=Math.max(0,(enemy.burn||0)-dt); enemy.statusTick=(enemy.statusTick||0)-dt; if(enemy.statusTick<=0&&(enemy.poison>0||enemy.burn>0)){enemy.statusTick=.35;const dotDamage=(enemy.poison>0?enemy.poisonDamage:0)+(enemy.burn>0?enemy.burnDamage:0);hurt(enemy,dotDamage*.35,enemy.burn>0?'#ff9d55':'#ae7cff');if(!enemies.includes(enemy))continue;} enemy.progress=Math.max(enemy.spawnProgress,enemy.progress+enemy.speed*dt*(enemy.slow > 0 ? enemy.slowFactor||.62 : 1)); enemy.slow=Math.max(0,enemy.slow-dt); if(!enemy.slow) enemy.slowFactor=1; enemy.hit=Math.max(0,enemy.hit-dt); const pos=pointOnPath(enemy.progress); enemy.x=pos.x; enemy.y=pos.y; enemy.angle=pos.angle; if(enemy.progress >= pathLength){ enemies.splice(enemies.indexOf(enemy),1); lives=Math.max(0,lives-enemy.damage); updateUI(); say(`${enemy.type.name} hit the keep for ${enemy.damage} damage!`); if(lives <= 0){ gameOver=true; running=false; recordStats({deaths:1}); showDeathUpgrades(); } } }
  for(const tower of towers) { tower.cooldown -= dt; tower.pulse=Math.max(0,tower.pulse-dt); const range=getTowerRange(tower), targets=enemies.filter(e=>distance(tower,e)<range); if(!targets.length) continue; const target=targets.reduce((best,e)=>e.progress>best.progress?e:best,targets[0]); tower.angle=Math.atan2(target.y-tower.y,target.x-tower.x); if(tower.type.kind === 'thorns'){ if(tower.cooldown <= 0){ targets.filter(e=>distance(tower,e)<range).forEach(enemy=>{applyThornAbility(tower,enemy);hurt(enemy,getTowerDamage(tower),tower.type.color);}); tower.cooldown=getTowerFireRate(tower); tower.pulse=.25; } } else if(tower.cooldown <= 0){ tower.cooldown=getTowerFireRate(tower); tower.pulse=.15; shots.push({x:tower.x,y:tower.y,target,tower,damage:getTowerDamage(tower),color:tower.type.color,kind:tower.type.kind,speed:tower.type.kind === 'spark' ? 720 : 410}); } }
  for(const shot of [...shots]) { if(!enemies.includes(shot.target)){ shots.splice(shots.indexOf(shot),1); continue; } const dx=shot.target.x-shot.x,dy=shot.target.y-shot.y,d=Math.hypot(dx,dy),move=shot.speed*dt; if(d < move+shot.target.r){ hurt(shot.target,shot.damage,shot.color); triggerShotAbility(shot); shots.splice(shots.indexOf(shot),1); } else { shot.x+=dx/d*move; shot.y+=dy/d*move; } }
  for(const p of particles){ p.life-=dt; p.x+=p.vx*dt; p.y+=p.vy*dt; p.vx*=.92; p.vy*=.92; } particles=particles.filter(p=>p.life>0);
  if(running && !spawnQueue.length && !enemies.length) endWave();
}

