function drawPortal() { const portal=pointOnPath(PORTAL_PROGRESS), active=running||spawnQueue.length>0, time=performance.now()/1000, pulse=1+Math.sin(time*5)*.11;ctx.save();ctx.translate(portal.x,portal.y);ctx.scale(1,pulse);ctx.fillStyle=active?'#5e27a9':'#2b466b';ctx.globalAlpha=.32;ctx.beginPath();ctx.arc(0,0,31,0,Math.PI*2);ctx.fill();ctx.globalAlpha=1;ctx.strokeStyle=active?'#e8a4ff':'#8ab4dc';ctx.lineWidth=5;ctx.beginPath();ctx.arc(0,0,23,0,Math.PI*2);ctx.stroke();ctx.strokeStyle=active?'#8eebff':'#517fa5';ctx.lineWidth=2;ctx.setLineDash([7,5]);ctx.rotate(active?time*2:0);ctx.beginPath();ctx.arc(0,0,16,0,Math.PI*2);ctx.stroke();ctx.setLineDash([]);ctx.fillStyle=active?'#c76bff':'#426c94';ctx.beginPath();ctx.arc(0,0,11,0,Math.PI*2);ctx.fill();if(active){for(let i=0;i<4;i++){const angle=time*3+i*Math.PI/2;ctx.fillStyle='#f4c4ff';ctx.beginPath();ctx.arc(Math.cos(angle)*29,Math.sin(angle)*29,3,0,Math.PI*2);ctx.fill();}}ctx.restore();ctx.fillStyle=active?'#ffe0ff':'#d4e7ff';ctx.font='bold 9px system-ui';ctx.fillText(active?'PORTAL ACTIVE':'PORTAL',portal.x-26,portal.y-38); }
