function draw() { ctx.clearRect(0,0,W,H);ctx.fillStyle='#0d2930';ctx.fillRect(0,0,W,H);ctx.save();ctx.translate(W/2,H/2);ctx.scale(camera.zoom,camera.zoom);ctx.translate(-camera.x,-camera.y);drawMap();drawLockedPads();drawPortal();for(const t of towers)drawPlacedTower(t);for(const e of enemies)drawEnemy(e);for(const s of shots){ctx.strokeStyle=s.color;ctx.lineWidth=s.kind==='spark'?3:5;ctx.beginPath();ctx.arc(s.x,s.y,s.kind==='spark'?3:5,0,Math.PI*2);ctx.stroke();}for(const p of particles){ctx.globalAlpha=Math.min(1,p.life*3);ctx.fillStyle=p.color;ctx.beginPath();ctx.arc(p.x,p.y,p.burst?(1-p.life)*38:p.size,0,Math.PI*2);ctx.fill();ctx.globalAlpha=1;}ctx.restore(); }
